using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;
using ResearchAgent;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to your OpenAI (or compatible) API key.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

var endpoint = Environment.GetEnvironmentVariable("OPENAI_BASE_URL");

// --- Build the chat client through the MEAI abstraction ---
OpenAIClientOptions? clientOptions = null;
if (endpoint is not null)
{
    clientOptions = new() { Endpoint = new Uri(endpoint) };
}

IChatClient chatClient = (clientOptions is not null
        ? new OpenAIClient(new System.ClientModel.ApiKeyCredential(apiKey), clientOptions)
        : new OpenAIClient(apiKey))
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Register tools ---
using var tools = new ResearchTools();

var agentTools = new AITool[]
{
    AIFunctionFactory.Create(tools.SearchWeb),
    AIFunctionFactory.Create(tools.FetchWebPage),
    AIFunctionFactory.Create(tools.SaveNote),
    AIFunctionFactory.Create(tools.GetNotes),
};

// --- Create the agent ---
var instructions = """
    You are a thorough research assistant. When given a topic:
    1. Search the web for relevant, up-to-date information using multiple queries.
    2. Fetch and read promising web pages for deeper detail.
    3. Save key findings as notes using the note-taking tool.
    4. After gathering enough information, retrieve your notes and produce a
       well-structured summary with sections, key facts, and source URLs.
    Be methodical: search, read, take notes, then summarize.
    """;

var agent = new ChatClientAgent(
    chatClient,
    name: "ResearchAgent",
    description: "Researches topics by searching the web and summarizing findings",
    instructions: instructions,
    tools: agentTools);

// --- Get the topic from the user ---
Console.ForegroundColor = ConsoleColor.Cyan;
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       AI Research Agent               ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.ResetColor();
Console.WriteLine();

string topic;
if (args.Length > 0)
{
    topic = string.Join(' ', args);
}
else
{
    Console.Write("Enter a research topic: ");
    topic = Console.ReadLine()?.Trim() ?? "";
}

if (string.IsNullOrWhiteSpace(topic))
{
    Console.Error.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine();
Console.ForegroundColor = ConsoleColor.DarkGray;
Console.WriteLine($"Researching: {topic}");
Console.WriteLine(new string('─', 50));
Console.ResetColor();

// --- Run the agent with streaming ---
var session = await agent.CreateSessionAsync(conversationId: null);

var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 4096,
});

var prompt = $"""
    Research the following topic and provide a comprehensive summary:

    **{topic}**

    Follow these steps:
    1. Search the web with 2-3 different search queries to get broad coverage.
    2. Fetch at least 2-3 of the most promising result pages.
    3. Save your key findings as notes (at least 3 notes).
    4. Retrieve your notes and write a final structured summary with:
       - An overview paragraph
       - Key findings (as bullet points)
       - Sources (URLs you consulted)
    """;

await foreach (var update in agent.RunStreamingAsync(prompt, session, runOptions))
{
    Console.Write(update.Text);
}

Console.WriteLine();

