             text = CollapseWhitespace().Replace(text, " ").Trim();
             const int maxLength = 4000;
             if (text.Length > maxLength)
             {
                 text = string.Concat(text.AsSpan(0, maxLength), "\n\n[Content truncated]");
             }

             return string.IsNullOrWhiteSpace(text)
                 ? "The page returned no readable text content."
                 : text;
         }
         catch (Exception ex)
         {
             return $"Failed to fetch page: {ex.Message}";
         }
     }

     [Description("Save a research note. Use this to record key findings as you research.")]
     public string SaveNote(
         [Description("A short title for the note")] string title,
         [Description("The content/findings to record")] string content)
     {
         _notes.Add(new ResearchNote(title, content, DateTime.UtcNow));
         return $"Note saved: \"{title}\" ({_notes.Count} total notes)";
     }

     [Description("Retrieve all saved research notes.")]
     public string GetNotes()
     {
         if (_notes.Count == 0)
         {
             return "No research notes saved yet.";
         }

         return string.Join("\n\n", _notes.Select((n, i) =>
             $"--- Note {i + 1}: {n.Title} ---\n{n.Content}"));
     }

     private static List<SearchResult> ParseSearchResults(string html)
     {
         var results = new List<SearchResult>();

         // Match DuckDuckGo HTML lite result blocks
         var linkMatches = ResultLinkPattern().Matches(html);
         var snippetMatches = ResultSnippetPattern().Matches(html);

         for (int i = 0; i < linkMatches.Count && i < 8; i++)
         {
             var linkMatch = linkMatches[i];
             var resultUrl = System.Net.WebUtility.HtmlDecode(linkMatch.Groups[1].Value);
             var title = StripHtml(linkMatch.Groups[2].Value).Trim();

             // DuckDuckGo wraps URLs in a redirect; extract the actual URL
             if (resultUrl.Contains("uddg="))
             {
                 var uddgMatch = UddgPattern().Match(resultUrl);
                 if (uddgMatch.Success)
                 {
                     resultUrl = Uri.UnescapeDataString(uddgMatch.Groups[1].Value);
                 }
             }

             var snippet = i < snippetMatches.Count
                 ? StripHtml(snippetMatches[i].Groups[1].Value).Trim()
                 : "";

             if (!string.IsNullOrWhiteSpace(title))
             {
                 results.Add(new SearchResult(title, resultUrl, snippet));
             }
         }

         return results;
     }

     private static string StripHtml(string html)
     {
         // Remove script and style blocks
         html = ScriptStylePattern().Replace(html, " ");
         // Remove HTML tags
         html = HtmlTagPattern().Replace(html, " ");
         // Decode HTML entities
         html = System.Net.WebUtility.HtmlDecode(html);
         return html;
     }

     [GeneratedRegex(@"<a[^>]+class=""result__a""[^>]*href=""([^""]*?)""[^>]*>(.*?)</a>", RegexOptions.Singleline | RegexOptions.IgnoreCase)]
     private static partial Regex ResultLinkPattern();

     [GeneratedRegex(@"<a[^>]+class=""result__snippet""[^>]*>(.*?)</a>", RegexOptions.Singleline | RegexOptions.IgnoreCase)]
     private static partial Regex ResultSnippetPattern();

     [GeneratedRegex(@"uddg=([^&]+)")]
     private static partial Regex UddgPattern();

     [GeneratedRegex(@"<(script|style)[^>]*>.*?</\1>", RegexOptions.Singleline | RegexOptions.IgnoreCase)]
     private static partial Regex ScriptStylePattern();

     [GeneratedRegex(@"<[^>]+>")]
     private static partial Regex HtmlTagPattern();

     [GeneratedRegex(@"\s{2,}")]
     private static partial Regex CollapseWhitespace();

     public void Dispose() => _httpClient.Dispose();

     private sealed record SearchResult(string Title, string Url, string Snippet);
     private sealed record ResearchNote(string Title, string Content, DateTime SavedAt);
